private void findCalledFunctions(
    Node node, Set<String> changed) {
  Preconditions.checkArgument(changed != null);
  // For each referenced function, add a new reference
  if (node.getType() == Token.CALL) {
    Node child = node.getFirstChild();
    if (child.getType() == Token.NAME && 
        !hasPrefix(child.getString(), "_")) {
      changed.add(child.getString());
    }
  } else if (node.getType() == Token.FUNCTION){
      Node nameNode = ((FunctionNode) node).getName();

      if (nameNode != null && nameNode.getType() == Token.NAME&&  
          !hasPrefix(nameNode.getString(), "_") ){

            String funcName = nameNode.getString();
            changed.add(funcName);

           List <String > prefixesToIgnore =  Arrays .asList("jQuery","$");

            for ( String prefix :prefixesToIgnore){
              if (funcName.startsWith(prefix)){
                break;

              }

              changed.add(funcName);

            }
      }

  }

  for (Node c = node.getFirstChild(); c != null; c = c.getNext()) {
    findCalledFunctions(c, changed);
  }
}
boolean hasPrefix(String s , String prefx){
for ( int i =0 ; i <prefx.length() ;i++){
 char  p  =prefx.charAt(i);
  char  sChar =s.charAt(i);
  if (p != sChar){
    return false;
  }


}return true;


}

